SELECT project_id, MAX(accuracy) AS highest_accuracy
FROM training_results
GROUP BY project_id;

SELECT AVG(max_accuracy) AS average_accuracy
FROM (
    SELECT project_id, MAX(accuracy) AS max_accuracy
    FROM training_results
    GROUP BY project_id
) AS subquery;

SELECT p.project_name, tr.classifier
FROM projects p
JOIN training_results tr ON p.project_id = tr.project_id;

SELECT project_name 
FROM projects 
WHERE project_id = 0;

SELECT COUNT(DISTINCT project_id) AS num_active_projects
FROM projects
WHERE status = 'active';

SELECT project_name
FROM projects
WHERE created_at = (SELECT MAX(created_at) FROM projects);

SELECT classifier, AVG(recall) AS avg_recall, AVG(precision) AS avg_precision
FROM training_results
GROUP BY classifier;

SELECT AVG(train_bug_per) AS average_bug_percentage
FROM training_results
WHERE train_bug_per > 50;
